      const measuredDuration = segmentEditorMeasuredVoiceoverDurations[segmentIndex] ?? null;
      if (!normalizedSourceUrl || measuredDuration?.sourceUrl !== normalizedSourceUrl) {
        return null;
      }

      return measuredDuration.durationSeconds;
