  const resolveSegmentReferenceAssetId = async (
    option: WorkspaceReferenceVisualOption,
    referenceKind: "character" | "scene",
    options?: {
      uploadKind?: string;
      uploadProjectId?: number | null;
      uploadRole?: string;
      uploadSegmentIndex?: number | null;
    },
  ) => {
    const shouldCopySavedCharacterReference =
      referenceKind === "character" &&
      option.source === "saved" &&
      option.previewKind !== "video" &&
      Boolean(option.assetId && segmentEditorDraft?.projectId);
    if (shouldCopySavedCharacterReference && option.assetId && segmentEditorDraft?.projectId) {
      const cacheKey = `project:${segmentEditorDraft.projectId}:saved-character:${option.key}:${option.assetId}`;
      const cachedAssetId = segmentReferenceFrameAssetIdsRef.current.get(cacheKey);
      if (cachedAssetId) {
        return cachedAssetId;
      }

      const copiedAssetId = await ensureStudioUploadedAssetId(
        {
          assetId: option.assetId,
          fileName: `character-reference-${option.assetId}.jpg`,
          mimeType: WORKSPACE_SEGMENT_REFERENCE_FRAME_MIME_TYPE,
          remoteUrl: buildWorkspaceMediaAssetProxyUrl(option.assetId),
        },
        {
          fallbackFileName: `character-reference-${option.assetId}.jpg`,
          fallbackMimeType: WORKSPACE_SEGMENT_REFERENCE_FRAME_MIME_TYPE,
          forceUpload: true,
          kind: "segment_source",
          language: selectedLanguage,
          mediaType: "photo",
          projectId: segmentEditorDraft.projectId,
          role: "segment_source",
          segmentIndex: option.sourceSegmentIndex,
        },
      );
      if (copiedAssetId) {
        segmentReferenceFrameAssetIdsRef.current.set(cacheKey, copiedAssetId);
        return copiedAssetId;
      }
    }

    if (option.assetId && option.previewKind !== "video") {
      return option.assetId;
    }

    const videoReferenceUrl = option.videoReferenceUrl?.trim();
    const shouldUseVideoFrame = option.previewKind === "video" && Boolean(videoReferenceUrl);
    if (option.assetId && !shouldUseVideoFrame) {
      return option.assetId;
    }

    if (!shouldUseVideoFrame || !videoReferenceUrl || !segmentEditorDraft?.projectId || !option.segment) {
      return null;
    }

    const cacheKey = `project:${segmentEditorDraft.projectId}:segment:${option.segment.index}:${option.key}`;
    const cachedAssetId = segmentReferenceFrameAssetIdsRef.current.get(cacheKey);
    if (cachedAssetId) {
      return cachedAssetId;
    }

    const frameFileName = `segment-${option.displayNumber ?? option.segment.index + 1}-reference-frame.jpg`;
    let frameAsset: StudioCustomVideoFile;
    try {
      frameAsset = {
        dataUrl: await extractWorkspaceVideoFrameDataUrl(videoReferenceUrl),
        fileName: frameFileName,
        fileSize: 0,
        mimeType: WORKSPACE_SEGMENT_REFERENCE_FRAME_MIME_TYPE,
      };
    } catch (error) {
      const posterReferenceUrl = option.videoPosterReferenceUrl?.trim();
      if (!posterReferenceUrl) {
        throw error;
      }

      frameAsset = {
        fileName: frameFileName,
        fileSize: 0,
        mimeType: WORKSPACE_SEGMENT_REFERENCE_FRAME_MIME_TYPE,
        remoteUrl: posterReferenceUrl,
      };
    }

    const hasUploadSegmentIndexOverride = Object.prototype.hasOwnProperty.call(options ?? {}, "uploadSegmentIndex");
    const assetId = await ensureStudioUploadedAssetId(frameAsset, {
      fallbackFileName: frameAsset.fileName,
      fallbackMimeType: frameAsset.mimeType,
      kind: options?.uploadKind ?? "segment_source",
      language: selectedLanguage,
      mediaType: "photo",
      projectId: options?.uploadProjectId ?? segmentEditorDraft.projectId,
      role: options?.uploadRole ?? "segment_source",
      segmentIndex: hasUploadSegmentIndexOverride ? options?.uploadSegmentIndex : option.segment.index,
    });
    if (!assetId) {
      throw new Error(
        referenceKind === "scene"
          ? workspaceText(locale, "Не удалось подготовить кадр видео для сцены.", "Could not prepare the video frame for the scene.")
          : workspaceText(locale, "Не удалось подготовить кадр видео для персонажа.", "Could not prepare the video frame for the character."),
      );
    }

    segmentReferenceFrameAssetIdsRef.current.set(cacheKey, assetId);
    return assetId;
  };
  const resolveSegmentReferenceSceneAssetIds = async (
    option: WorkspaceReferenceVisualOption | null,
  ) => {
    if (!option) {
      return [];
    }

    const assetId = await resolveSegmentReferenceAssetId(option, "scene");
    if (!assetId) {
      throw new Error(workspaceText(locale, "У этой сцены нет доступного фото или видео для референса.", "This scene has no available photo or video reference."));
    }

    return [assetId];
  };
  const resolveSegmentReferenceCharacterAssetIds = async (
    options: WorkspaceReferenceVisualOption[],
    resolveOptions: { allowMissing?: boolean } = {},
  ) => {
    const assetIds: number[] = [];
    for (const option of options) {
      if (option.source === "project-character") {
        continue;
      }

      let assetId: number | null = null;
      try {
        assetId = await resolveSegmentReferenceAssetId(option, "character");
      } catch (error) {
        if (!resolveOptions.allowMissing) {
          throw error;
        }

        console.warn("[workspace] Skipping unavailable character reference asset.", {
          error,
          key: option.key,
          label: option.label,
        });
        continue;
      }
      if (!assetId) {
        if (resolveOptions.allowMissing) {
          console.warn("[workspace] Skipping character reference without an available image.", {
            key: option.key,
            label: option.label,
          });
          continue;
        }
        throw new Error(workspaceText(locale, "У персонажа нет доступного фото для референса.", "This character has no available image reference."));
      }
      assetIds.push(assetId);
    }

    return assetIds;
  };
  const resolvePromptScopedSegmentReferenceCharacters = (promptValue: string) => {
    const mentionedOptions = resolveWorkspacePromptMentionedCharacterOptions(
      promptValue,
      selectedSegmentReferenceCharacterOptions,
    );
    const characterReferenceOptions =
      mentionedOptions.length > 0
        ? mentionedOptions
        : selectedSegmentReferenceCharacterOptions;
    const characterIds = characterReferenceOptions
      .map((option) => {
        if (option.source !== "project-character") {
          return null;
        }

        const match = option.key.match(/^project-character:(\d+)$/);
        return match ? getPositiveWorkspaceMediaAssetId(match[1]) : null;
      })
      .filter((characterId): characterId is number => typeof characterId === "number" && characterId > 0);

    return {
      characterIds,
      characterReferenceOptions,
      isPromptScoped: mentionedOptions.length > 0,
    };
  };
  const resolveSegmentPromptCharacterBillingQuality = (
    promptValue: string,
    quality: StudioSegmentVisualQuality,
  ) => resolveWorkspacePromptCharacterBillingQuality(promptValue, selectedSegmentReferenceCharacterOptions, quality);
  const segmentEditorPendingDeleteSegment =
    typeof segmentEditorPendingDeleteIndex === "number"
      ? segmentEditorDraft?.segments.find((segment) => segment.index === segmentEditorPendingDeleteIndex) ?? null
      : null;
  const segmentEditorPendingDeleteDisplayNumber =
    segmentEditorDraft && segmentEditorPendingDeleteSegment
      ? getWorkspaceSegmentEditorDisplayNumber(segmentEditorDraft.segments, segmentEditorPendingDeleteSegment.index)
      : null;
  const segmentEditorPendingDeleteSummary = segmentEditorPendingDeleteSegment
    ? `${workspaceText(
        locale,
        `Сцена ${segmentEditorPendingDeleteDisplayNumber ?? segmentEditorPendingDeleteSegment.index + 1}`,
        `Scene ${segmentEditorPendingDeleteDisplayNumber ?? segmentEditorPendingDeleteSegment.index + 1}`,
      )} · ${formatWorkspaceSegmentEditorSegmentTimeRange(
        getWorkspaceSegmentEditorDisplayStartTime(segmentEditorPendingDeleteSegment),
        getWorkspaceSegmentEditorDisplayEndTime(segmentEditorPendingDeleteSegment),
        { isFirstSegment: segmentEditorPendingDeleteDisplayNumber === 1 },
      )}`
    : "";
  const segmentSubtitleBulkTextDefault = segmentEditorDraft
    ? buildWorkspaceSegmentBulkSubtitleText(segmentEditorDraft.segments)
    : "";
  const segmentSubtitleBulkTextValue = hasEditedSegmentSubtitleBulkTextInput
    ? segmentSubtitleBulkTextInput
    : segmentSubtitleBulkTextDefault;
  useEffect(() => {
    clearSegmentTimelineBulkVoiceTextEditSnapshot();
    setHasEditedSegmentSubtitleBulkTextInput(false);
    setSegmentSubtitleBulkTextInput("");
    setSegmentSubtitleBulkTextError(null);
  }, [clearSegmentTimelineBulkVoiceTextEditSnapshot, segmentEditorDraft?.projectId]);
  useEffect(() => {
    setSelectedSegmentReferenceCharacterIds([]);
    setSelectedSegmentReferenceCharacterAssetKeys([]);
    setSegmentTalkingCharacterTargets({});
    setSelectedSegmentReferenceSceneKey(null);
    setIsSegmentReferencesModalOpen(false);
    setIsWorkspaceReferenceCreatorOpen(false);
    setReferenceCreationSource("ai");
    setReferenceCreationPrompt(WORKSPACE_REFERENCE_CHARACTER_DEFAULTS.description);
    setReferenceCreationUploadFile(null);
    setReferenceCreationPreviewReference(null);
    setReferenceCreationProjectKey(null);
    setReferenceCreationCharacterGender(WORKSPACE_REFERENCE_CHARACTER_DEFAULTS.gender);
    setReferenceCreationCharacterAgeRange(WORKSPACE_REFERENCE_CHARACTER_DEFAULTS.ageRange);
    setReferenceCreationCharacterStyle(WORKSPACE_REFERENCE_CHARACTER_DEFAULTS.style);
    setReferenceCreationScenePlaceType(WORKSPACE_REFERENCE_SCENE_DEFAULTS.placeType);
    setReferenceCreationSceneStyle(WORKSPACE_REFERENCE_SCENE_DEFAULTS.style);
    setReferenceCreationSceneLightingMood(WORKSPACE_REFERENCE_SCENE_DEFAULTS.lightingMood);
    setSavedWorkspaceReferencesNotice(null);
  }, [segmentEditorDraft?.projectId]);
  useEffect(() => {
    const objectUrl = referenceCreationUploadFile?.objectUrl;
    return () => {
      if (objectUrl?.startsWith("blob:")) {
        URL.revokeObjectURL(objectUrl);
      }
    };
  }, [referenceCreationUploadFile?.objectUrl]);
  useEffect(() => {
    const projectId = segmentEditorDraft?.projectId;
    if (!projectId) {
      setSegmentProjectCharacters([]);
      setSegmentProjectCharactersError(null);
      setIsSegmentProjectCharactersLoading(false);
      return undefined;
    }

    let isCancelled = false;
    setIsSegmentProjectCharactersLoading(true);
    setSegmentProjectCharactersError(null);

    void (async () => {
      try {
        const response = await fetch(`/api/studio/projects/${encodeURIComponent(String(projectId))}/characters?bootstrap=false`);
        const payload = (await response.json().catch(() => null)) as WorkspaceProjectCharactersResponse | null;
        if (!response.ok || !payload?.data) {
          throw new Error(payload?.error ?? "Не удалось загрузить персонажей проекта.");
        }
        if (isCancelled) {
          return;
        }
        setSegmentProjectCharacters(
          (payload.data.characters ?? []).map(normalizeWorkspaceProjectCharacter).filter(Boolean) as WorkspaceProjectCharacter[],
        );
      } catch (error) {
        if (isCancelled) {
          return;
        }
        setSegmentProjectCharacters([]);
        setSegmentProjectCharactersError(error instanceof Error ? error.message : "Не удалось загрузить персонажей проекта.");
      } finally {
        if (!isCancelled) {
          setIsSegmentProjectCharactersLoading(false);
        }
      }
    })();

    return () => {
      isCancelled = true;
    };
  }, [segmentEditorDraft?.projectId]);
